// Config
const CFG = {
  SUPABASE_URL: 'https://hkqssbomrcbtfbdowtgj.supabase.co',
  SUPABASE_KEY: '{{REPLACE_WITH_SUPABASE_SERVICE_ROLE_KEY}}',
  MONDAY_TOKEN: '{{REPLACE_WITH_MONDAY_TOKEN_OBSOLETE}}',
  MONDAY_BOARD_ID: 18399476470
};

const body = $input.first().json.body || $input.first().json;

const required = ['event_id','lead_email','channel','direction','content','timestamp'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) throw new Error('Missing fields: ' + missing.join(', '));

const validChannels = ['email','linkedin','voice','sms'];
const validDirections = ['inbound','outbound'];
const validIntents = ['unknown','no_action','not_interested','referral','already_have_contract','interested','booking'];
const validContentTypes = ['message','transcript','summary'];

if (!validChannels.includes(body.channel)) throw new Error('Invalid channel: ' + body.channel);
if (!validDirections.includes(body.direction)) throw new Error('Invalid direction: ' + body.direction);

let phone = body.phone_e164 || null;
if (phone && !/^\+[1-9]\d{7,14}$/.test(phone)) phone = null;

return [{ json: {
  ...CFG,
  event_id: body.event_id.toLowerCase(),
  lead_email: body.lead_email.toLowerCase().trim(),
  timestamp: body.timestamp,
  channel: body.channel,
  direction: body.direction,
  content: body.content,
  content_type: validContentTypes.includes(body.content_type) ? body.content_type : 'message',
  sender_name: body.sender_name || '',
  intent: validIntents.includes(body.intent) ? body.intent : 'unknown',
  metadata: body.metadata || {},
  workflow_execution_id: body.workflow_execution_id || '',
  phone_e164: phone,
  full_name: body.full_name || '',
  company: body.company || '',
  linkedin_urn: body.linkedin_urn || null,
  linkedin_profile_url: body.linkedin_profile_url || null,
  aimfox_campaign: body.aimfox_campaign || null,
  email_sender_inbox: body.email_sender_inbox || null,
  trigger_cross_channel: body.trigger_cross_channel === true,
  trigger_cross_channel_str: body.trigger_cross_channel === true ? 'yes' : 'no',
  target_channels: Array.isArray(body.target_channels) ? body.target_channels : [],
  follow_up_context: body.follow_up_context || ''
}}];

// Merge RPC result back with original setup data
const setup = $('Setup & Validate').first().json;
const rpcResp = $input.first().json;
const lead = Array.isArray(rpcResp) && rpcResp.length > 0 ? rpcResp[0] : {};
return [{ json: {
  ...setup,
  monday_item_id: lead.monday_item_id || null,
  overall_intent: lead.overall_intent || setup.intent
}}];

// RPC returns { was_new: bool, event_id: '...' }
// Use 'yes'/'no' strings for was_inserted_str — n8n string comparisons are reliable
const setup = $('Merge Lead Data').first().json;
const rpcResp = $input.first().json;
const wasNew = rpcResp && rpcResp.was_new === true;
return [{ json: { ...setup, was_inserted: wasNew, was_inserted_str: wasNew ? 'yes' : 'no', insert_resp: rpcResp } }];

const d = $('Extract Monday ID').first().json;
const scheduled = new Date(Date.now() + 30*60*1000).toISOString();
return (d.target_channels || []).map(tc => ({ json: {
  ...d,
  queue_row: {
    lead_email: d.lead_email,
    trigger_channel: d.channel,
    target_channel: tc,
    trigger_event_id: d.event_id,
    scheduled_for: scheduled,
    status: 'pending',
    follow_up_context: d.follow_up_context || 'Lead showed interest via ' + d.channel
  }
}}));

