// Parse Notion query response, compute COALESCE'd update_props.
const results = $input.first().json.results || [];
const setup = $('Setup & Validate').item.json;
const upsertIntent = ($('Upsert Lead').item.json.overall_intent) || setup.intent || 'unknown';

// Always-update fields: intent (canonical), last channel, last activity.
const updateProps = {
  "Overall intent": { select: { name: upsertIntent } },
  "Last channel":   { select: { name: setup.channel } },
  "Last activity":  { date:   { start: setup.timestamp } }
};

if (results.length > 0) {
  const existing = results[0].properties || {};
  const emptyRT    = (p) => !p || !Array.isArray(p.rich_text) || p.rich_text.length === 0;
  const emptyEmail = (p) => !p || p.email === null || p.email === undefined;
  const emptyPhone = (p) => !p || p.phone_number === null || p.phone_number === undefined;
  const emptyUrl   = (p) => !p || p.url === null || p.url === undefined;

  // COALESCE: only fill empty fields on the existing Notion lead.
  if (setup.company && emptyRT(existing["Company"]))
    updateProps["Company"] = { rich_text: [{ text: { content: setup.company } }] };
  if (setup.phone_e164 && emptyPhone(existing["Phone"]))
    updateProps["Phone"] = { phone_number: setup.phone_e164 };
  if (setup.linkedin_profile_url && emptyUrl(existing["LinkedIn URL"]))
    updateProps["LinkedIn URL"] = { url: setup.linkedin_profile_url };
  if (setup.linkedin_urn && emptyRT(existing["LinkedIn URN"]))
    updateProps["LinkedIn URN"] = { rich_text: [{ text: { content: setup.linkedin_urn } }] };
  if (setup.aimfox_campaign && emptyRT(existing["Aimfox campaign"]))
    updateProps["Aimfox campaign"] = { rich_text: [{ text: { content: setup.aimfox_campaign } }] };
  if (setup.email_sender_inbox && emptyEmail(existing["Sender inbox"]))
    updateProps["Sender inbox"] = { email: setup.email_sender_inbox };

  return [{ json: {
    found: true,
    notion_lead_id: results[0].id,
    update_props: updateProps,
    ...setup
  }}];
}

return [{ json: {
  found: false,
  notion_lead_id: null,
  update_props: null,
  ...setup
}}];

