    "Timestamp":    { date:   { start: s.timestamp } },
    "Intent":       { select: { name: s.intent || "unknown" } },
    "Content":      { rich_text: [{ text: { content: (s.content || "").slice(0, 1900) } }] },
    "Content type": { select: { name: s.content_type || "message" } },
    "Event ID":     { rich_text: [{ text: { content: s.event_id } }] }
  };
  if (s.sender_name)           props["Sender name"]      = { rich_text: [{ text: { content: s.sender_name } }] };
  if (s.workflow_execution_id) props["Workflow exec ID"] = { rich_text: [{ text: { content: s.workflow_execution_id } }] };
  const body = {
    parent: { database_id: "362dc227-748f-817b-b406-cf43be6f4822" },
    properties: props
  };
  if (s.content) {
    body.children = [{
      object: "block", type: "paragraph",
      paragraph: { rich_text: [{ type: "text", text: { content: String(s.content).slice(0, 1900) } }] }
    }];
  }
  return body;
})()) }}

